    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public async Task ChargeAsync_ValidCardTokenAndPositiveAmount_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = "tok_valid_123";
        var amount = 49.99m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // ChargeAsync вҖ” null / empty card token
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    [DataRow(null, DisplayName = "Null card token")]
    [DataRow("", DisplayName = "Empty card token")]
    public async Task ChargeAsync_NullOrEmptyCardToken_ThrowsNotImplementedException(string? cardToken)
    {
        // Arrange
        var amount = 10.00m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken!, amount));
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // ChargeAsync вҖ” zero amount
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = "tok_zero";
        var amount = 0m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // ChargeAsync вҖ” negative amount
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsNotImplementedException()
    {
        // Arrange
        var cardToken = "tok_negative";
        var amount = -5.00m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // RefundAsync вҖ” valid charge ID (NotImplementedException)
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ThrowsNotImplementedException()
    {
        // Arrange
        var chargeId = "ch_abc123";

        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId));
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // RefundAsync вҖ” null / empty charge ID
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    [DataRow(null, DisplayName = "Null charge ID")]
    [DataRow("", DisplayName = "Empty charge ID")]
    public async Task RefundAsync_NullOrEmptyChargeId_ThrowsNotImplementedException(string? chargeId)
    {
        // Act & Assert
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(chargeId!));
    }
}

